-    static void checkValueClass() {
-        boolean transformed = !Point.class.isIdentity();
-
-        try (var is = Point.class.getResourceAsStream("AddAll$Point.class")) {
-            if (is == null) {
-                throw new RuntimeException("Cannot read Point.class");
